  async function savePayrollLine(line?:PayrollBudgetLine){const category=window.prompt("Categoría: NOMINAS_FIJAS, OTRAS_NOMINAS u OTRAS_REMUNERACIONES",line?.category||"NOMINAS_FIJAS")?.trim().toUpperCase();if(!category||!["NOMINAS_FIJAS","OTRAS_NOMINAS","OTRAS_REMUNERACIONES"].includes(category))return;const payrollType=window.prompt("Tipo de nómina o remuneración:",line?.payroll_type||"")?.trim();if(!payrollType)return;const fund=window.prompt("Fondo de ejecución:",line?.execution_fund||"30")?.trim();if(!fund)return;const program=Number(window.prompt("Programa:",String(line?.program??1)));const subproduct=Number(window.prompt("Subproducto:",String(line?.subproduct??0)));const activity=Number(window.prompt("Actividad:",String(line?.activity??1)));const monthlyAmount=Number(window.prompt("Sueldo o monto mensual:",String(line?.monthly_amount??0)));if([program,subproduct,activity,monthlyAmount].some(value=>!Number.isFinite(value)||value<0)){setPayrollMessage("Revise los valores numéricos de la partida.");return;}const response=await fetch("/api/hr/payroll-budget",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({id:line?.id||null,budget_year:payrollYear,category,payroll_type:payrollType,execution_fund:fund,program,subproduct,activity,monthly_amount:monthlyAmount})});const data=await response.json();setPayrollMessage(response.ok?"Partida de nómina guardada correctamente.":data.error||"No fue posible guardar la partida.");if(response.ok)await loadPayrollBudget();}
  async function savePayrollCap(cap:PayrollBudgetCap){const amount=Number(window.prompt(`Tope mensual del fondo ${cap.execution_fund}:`,String(cap.monthly_cap)));if(!Number.isFinite(amount)||amount<0)return;const response=await fetch("/api/hr/payroll-budget",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"cap",year:payrollYear,fund:cap.execution_fund,amount})});const data=await response.json();setPayrollMessage(response.ok?"Tope mensual actualizado.":data.error||"No fue posible actualizar el tope.");if(response.ok)await loadPayrollBudget();}
