  async function handleAuth(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    setAuthBusy(true);
    setAuthError("");
    const fd = new FormData(e.currentTarget);
    const username = String(fd.get("username") || "").trim();
    const password = String(fd.get("password") || "");
    if (!username || username.length < 3) {
      setAuthError("El usuario debe tener al menos 3 caracteres.");
      setAuthBusy(false);
      return;
    }
    if (password.length < 6) {
      setAuthError("La contraseña debe tener al menos 6 caracteres.");
      setAuthBusy(false);
      return;
    }
    const response = await fetch("/api/auth/login", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ username, password }),
    });
    const result = await response.json();
    if (!response.ok) setAuthError(result.error || "No fue posible completar la solicitud.");
    else setCurrentUser(result.user);
    setAuthBusy(false);
  }

  async function logout() {
    await fetch("/api/auth/logout", { method: "POST" });
    setCurrentUser(null);
  }

  async function updateUser(user: ManagedUser, changes: Partial<ManagedUser>) {
    setUsersMessage("");
    const updated = { ...user, ...changes };
    const suspensionReason = changes.active === false ? window.prompt("Motivo de la suspensión:", "Suspendido por el administrador") || "" : "";
    const response = await fetch("/api/users", { method: "PATCH", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ id: updated.id, role: updated.role, area: updated.area, department: updated.department || "", active: updated.active, suspensionReason }) });
    const result = await response.json();
    if (!response.ok) setUsersMessage(result.error || "No se pudo actualizar el usuario.");
    else { setUsers(previous => previous.map(item => item.id === updated.id ? updated : item)); setUsersMessage("Cambios guardados correctamente."); }
  }

  async function updatePermissions(user:ManagedUser,key:keyof Permissions,enabled:boolean){const permissions={...(user.permissions||{}),[key]:enabled};const response=await fetch("/api/users",{method:"PATCH",headers:{"Content-Type":"application/json"},body:JSON.stringify({id:user.id,permissions})});const result=await response.json();if(!response.ok)setUsersMessage(result.error||"No se pudieron actualizar los permisos.");else{setUsers(items=>items.map(item=>item.id===user.id?{...item,permissions}:item));setPermissionUser(current=>current?.id===user.id?{...current,permissions}:current);setUsersMessage("Permisos guardados correctamente.");}}

  async function createManagedUser(e:React.FormEvent<HTMLFormElement>){e.preventDefault();setUsersMessage("");const fd=new FormData(e.currentTarget);const permissionKeys=permissionGroups.flatMap(group=>group.items.map(item=>item.key));const permissions=Object.fromEntries(permissionKeys.map(key=>[key,fd.get(key)==="on"]));const response=await fetch("/api/users",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({username:String(fd.get("username")),password:String(fd.get("password")),fullName:String(fd.get("fullName")),area:String(fd.get("area")),role:String(fd.get("role")),permissions})});const result=await response.json();if(!response.ok){setUsersMessage(result.error||"No fue posible crear el usuario.");return;}setShowCreateUser(false);setUsers(items=>[...items,result.user]);setUsersMessage("Usuario creado con contraseña temporal.");}

  async function createCatalogItem(e:React.FormEvent<HTMLFormElement>){e.preventDefault();if(!showCatalogForm)return;const fd=new FormData(e.currentTarget);const response=await fetch("/api/catalogs",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({type:showCatalogForm,code:String(fd.get("code")||""),name:String(fd.get("name")||""),description:String(fd.get("description")||"")})});const result=await response.json();if(!response.ok){setCatalogMessage(result.error||"No fue posible guardar el registro.");return;}setShowCatalogForm(null);setCatalogMessage("Registro agregado correctamente.");await loadCatalogs();}
  async function toggleCatalog(type:string,item:CatalogItem){const response=await fetch("/api/catalogs",{method:"PATCH",headers:{"Content-Type":"application/json"},body:JSON.stringify({type,id:item.id,code:item.code||"",name:item.name||"",description:item.description||"",active:!item.active})});const result=await response.json();if(!response.ok)setCatalogMessage(result.error||"No fue posible actualizar el registro.");else{setCatalogMessage("Catálogo actualizado correctamente.");await loadCatalogs();}}

  async function changeFirstPassword(e:React.FormEvent<HTMLFormElement>){e.preventDefault();setAuthBusy(true);setAuthError("");const fd=new FormData(e.currentTarget);const password=String(fd.get("password")||"");const confirmation=String(fd.get("confirmation")||"");if(password.length<8){setAuthError("La nueva contraseña debe tener al menos 8 caracteres.");setAuthBusy(false);return;}if(password!==confirmation){setAuthError("Las contraseñas no coinciden.");setAuthBusy(false);return;}const response=await fetch("/api/auth/change-password",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({password})});const result=await response.json();if(!response.ok)setAuthError(result.error||"No fue posible cambiar la contraseña.");else setCurrentUser(result.user);setAuthBusy(false);}

  function canView(key:keyof Permissions){return currentUser?.role==="Administrador"||Boolean(currentUser?.permissions?.[key]);}
  function canSeeModule(module:DirectionModule,direction:InstitutionalDirection){if(currentUser?.role==="Administrador")return true;if(module.adminOnly)return false;if(module.roles&&!module.roles.includes(currentUser?.role||""))return false;if(module.permission&&!canView(module.permission))return false;if(direction.area&&module.permission===undefined)return currentUser?.area===direction.area;return true;}

  async function createMeasurement(e:React.FormEvent<HTMLFormElement>){e.preventDefault();setMeasurementMessage("");const fd=new FormData(e.currentTarget);const response=await fetch("/api/cubicaciones",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({projectId:fd.get("projectId"),amount:Number(fd.get("amount")),progress:Number(fd.get("progress")),description:String(fd.get("description"))})});const result=await response.json();if(!response.ok){setMeasurementMessage(result.error||"No se pudo registrar la cubicación.");return;}setShowMeasurementForm(false);setMeasurementMessage(`Cubicación ${result.code} registrada correctamente.`);await loadMeasurements();await loadTechnicalProjects();}

  async function transitionMeasurement(measurement:Measurement,action:"ADVANCE"|"RETURN"){const next=action==="RETURN"?(measurement.status==="Revisada"?"Cubicada":"Revisada"):(measurement.status==="Cubicada"?"Revisada":measurement.status==="Revisada"?"Libramiento":measurement.status==="Libramiento"?"Pagada":null);if(!next)return;const comments=window.prompt(action==="RETURN"?`Observación obligatoria para devolver a ${next}:`:`Comentario para avanzar a ${next}:`)||"";if(action==="RETURN"&&comments.trim().length<5){setMeasurementMessage("Debe indicar una observación para devolver la cubicación.");return;}const response=await fetch("/api/cubicaciones",{method:"PATCH",headers:{"Content-Type":"application/json"},body:JSON.stringify({id:measurement.id,action,comments})});const result=await response.json();if(!response.ok)setMeasurementMessage(result.error||"No se pudo cambiar el estado de la cubicación.");else{setMeasurementMessage(action==="RETURN"?`Cubicación devuelta a ${next}.`:`Cubicación avanzada a ${next}.`);await loadMeasurements();await loadTechnicalProjects();}}
  function canAdvanceMeasurement(status:Measurement["status"]){if(currentUser?.role==="Administrador")return status!=="Pagada";const key=status==="Cubicada"?"revisar_cubicaciones":status==="Revisada"?"libramiento_cubicaciones":status==="Libramiento"?"pagar_cubicaciones":null;return key?Boolean(currentUser?.permissions?.[key as keyof Permissions]):false;}
  function canReturnMeasurement(status:Measurement["status"]){if(!["Revisada","Libramiento"].includes(status))return false;if(currentUser?.role==="Administrador")return true;const key=status==="Revisada"?"revisar_cubicaciones":"libramiento_cubicaciones";return Boolean(currentUser?.permissions?.[key]);}
  async function addMeasurementDocument(measurement:Measurement){const documentName=window.prompt("Nombre del documento:")?.trim();if(!documentName)return;const documentUrl=window.prompt("Enlace HTTPS del documento:")?.trim();if(!documentUrl)return;const response=await fetch("/api/cubicaciones",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({id:measurement.id,documentName,documentUrl})});const result=await response.json();if(!response.ok)setMeasurementMessage(result.error||"No fue posible adjuntar el documento.");else{setMeasurementMessage("Documento agregado al expediente.");await loadMeasurements();}}
  async function addBudgetModification(project:BudgetProject){const type=window.prompt("Tipo: PRESUPUESTO o APROPIACION","APROPIACION")?.trim().toUpperCase();if(!type)return;const amount=Number(window.prompt("Monto de la modificación (use negativo para reducción):","0"));const description=window.prompt("Justificación de la modificación:")?.trim()||"";const reference=window.prompt("Referencia o documento de soporte:")?.trim()||"";const response=await fetch("/api/budget",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({projectId:project.id,type,amount,description,reference})});const result=await response.json();if(!response.ok)setBudgetMessage(result.error||"No fue posible registrar la modificación.");else{setBudgetMessage("Modificación presupuestaria registrada.");await loadBudget();}}
